function lin = fGetTextLineV01(fName,nmb)%% get a line from any text file%% lin = fGetTextLineV01(fName,nmb)%% fName: file name (full path)% nmb:  number of line% lin: line output%% Function fGetTextLineV01.m % get a line from a text file, ver.1% Kei Nakamura% Created on Friday, february 18th 2011.% Modified on %% ver.1: created%% main bodyfid = fopen(fName);     % file open('name','permission')   for i=1:nmb              % density info in 5th line    lin = fgetl(fid);endfclose(fid);
